class UUIDGenerator {
  static final Random _random = Random.secure();

  /// Generates a UUID v4 compliant string.
  /// Format: xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx
  /// where x is any hex digit and y is one of 8, 9, a, or b.
  static String generateV4() {
    final bytes = List<int>.generate(16, (_) => _random.nextInt(256));

    // Set version to 4 (0100 in binary) — byte 6, high nibble
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set variant to RFC 4122 (10xx in binary) — byte 8, high 2 bits
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    final hex = bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).toList();

    return '${hex.sublist(0, 4).join()}-'
        '${hex.sublist(4, 6).join()}-'
        '${hex.sublist(6, 8).join()}-'
        '${hex.sublist(8, 10).join()}-'
        '${hex.sublist(10, 16).join()}';
  }

  /// Generates a short unique ID (8 hex characters) for compact usage.
  static String generateShort() {
    final bytes = List<int>.generate(4, (_) => _random.nextInt(256));
    return bytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
  }

  /// Generates a timestamp-prefixed UUID for sortable offline records.
  /// Format: <timestamp_hex>-<random_hex>
  static String generateTimestampBased() {
    final timestamp =
        DateTime.now().millisecondsSinceEpoch.toRadixString(16).padLeft(12, '0');
    final randomBytes = List<int>.generate(10, (_) => _random.nextInt(256));
    final randomHex =
        randomBytes.map((b) => b.toRadixString(16).padLeft(2, '0')).join();
    return '${timestamp.substring(0, 8)}-'
        '${timestamp.substring(8, 12)}-'
        '${randomHex.substring(0, 4)}-'
        '${randomHex.substring(4, 8)}-'
        '${randomHex.substring(8, 20)}';
  }
}

enum UUIDType { v4, short, timestampBased }

class OfflineRecord {
  final String id;
  final String title;
  final String description;
  final DateTime createdAt;
  final UUIDType idType;
  bool synced;

  OfflineRecord({
    required this.id,
    required this.title,
    required this.description,
    required this.createdAt,
    required this.idType,
    this.synced = false,
  });
}

