  }

  void _generateNewId() {
    setState(() {
      switch (_selectedType) {
        case UUIDType.v4:
          _currentGeneratedId = UUIDGenerator.generateV4();
          break;
        case UUIDType.short:
          _currentGeneratedId = UUIDGenerator.generateShort();
          break;
        case UUIDType.timestampBased:
          _currentGeneratedId = UUIDGenerator.generateTimestampBased();
          break;
      }
    });
  }

  void _copyToClipboard(String text) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Copied: $text'),
        duration: const Duration(seconds: 1),
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _createRecord() {
    if (_titleController.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('Please enter a title for the record.'),
          behavior: SnackBarBehavior.floating,
        ),
      );
      return;
    }

    String newId;
    switch (_selectedType) {
      case UUIDType.v4:
        newId = UUIDGenerator.generateV4();
        break;
      case UUIDType.short:
        newId = UUIDGenerator.generateShort();
        break;
      case UUIDType.timestampBased:
        newId = UUIDGenerator.generateTimestampBased();
        break;
    }

    setState(() {
      _records.insert(
        0,
        OfflineRecord(
          id: newId,
          title: _titleController.text.trim(),
          description: _descriptionController.text.trim(),
          createdAt: DateTime.now(),
          idType: _selectedType,
        ),
      );
    });

    _titleController.clear();
    _descriptionController.clear();

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Record created with ID: $newId'),
        duration: const Duration(seconds: 2),
        behavior: SnackBarBehavior.floating,
      ),
    );

    _tabController.animateTo(2);
  }

  void _simulateSync() {
    final unsyncedCount = _records.where((r) => !r.synced).length;
    if (unsyncedCount == 0) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(
          content: Text('All records are already synced!'),
          behavior: SnackBarBehavior.floating,
        ),
      );
      return;
    }

    setState(() {
      for (var record in _records) {
        record.synced = true;
      }
    });

    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('$unsyncedCount record(s) synced successfully!'),
        behavior: SnackBarBehavior.floating,
        backgroundColor: Colors.green,
      ),
    );
  }

  void _deleteRecord(int index) {
    final removed = _records[index];
    setState(() {
      _records.removeAt(index);
    });
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Deleted record: ${removed.title}'),
        behavior: SnackBarBehavior.floating,
        action: SnackBarAction(
          label: 'Undo',
          onPressed: () {
            setState(() {
              _records.insert(index, removed);
            });
          },
        ),
      ),
    );
  }

